//\! Middleware stack visualization component.

use crate::{RichOutput, OutputMode};

/// Information about a single middleware layer.
#[derive(Debug, Clone)]
pub struct MiddlewareInfo {
    pub name: String,
    pub type_name: String,
    pub order: usize,
    pub can_short_circuit: bool,
    pub config_summary: Option<String>,
}

impl MiddlewareInfo {
    pub fn new(name: &str, order: usize) -> Self {
        Self {
            name: name.to_string(),
            type_name: name.to_string(),
            order,
            can_short_circuit: false,
            config_summary: None,
        }
    }

    pub fn with_config(mut self, config: &str) -> Self {
        self.config_summary = Some(config.to_string());
        self
    }

    pub fn short_circuits(mut self) -> Self {
        self.can_short_circuit = true;
        self
    }
}

/// Middleware stack display.
#[derive(Debug, Clone)]
pub struct MiddlewareStackDisplay {
    middlewares: Vec<MiddlewareInfo>,
    show_config: bool,
    show_flow: bool,
}

impl MiddlewareStackDisplay {
    pub fn new(middlewares: Vec<MiddlewareInfo>) -> Self {
        Self {
            middlewares,
            show_config: true,
            show_flow: true,
        }
    }

    pub fn hide_config(mut self) -> Self {
        self.show_config = false;
        self
    }

    pub fn hide_flow(mut self) -> Self {
        self.show_flow = false;
        self
    }

    pub fn render(&self, output: &RichOutput) {
        eprintln\!("[DEBUG] MiddlewareStackDisplay::render() count={}", self.middlewares.len());
        match output.mode() {
            OutputMode::Rich => self.render_rich(output),
            OutputMode::Plain | OutputMode::Minimal => self.render_plain(output),
        }
    }

    fn render_plain(&self, output: &RichOutput) {
        output.print(&format\!("Middleware Stack ({} layers):", self.middlewares.len()));

        for mw in &self.middlewares {
            let sc = if mw.can_short_circuit { " [short-circuit]" } else { "" };
            output.print(&format\!("  {}. {}{}", mw.order, mw.name, sc));

            if self.show_config {
                if let Some(config) = &mw.config_summary {
                    output.print(&format\!("     config: {}", config));
                }
            }
        }

        // Handler
        output.print(&format\!("  {}. [Handler]", self.middlewares.len() + 1));

        if self.show_flow && \!self.middlewares.is_empty() {
            let flow: Vec<String> = (1..=self.middlewares.len() + 1)
                .rev()
                .map(|n| n.to_string())
                .collect();
            output.print(&format\!("\nResponse flow: {}", flow.join(" -> ")));
        }
    }

    fn render_rich(&self, output: &RichOutput) {
        self.render_plain(output);
    }

    pub fn as_plain_text(&self) -> String {
        let mut lines = vec\![];
        lines.push(format\!("Middleware Stack ({} layers):", self.middlewares.len()));

        for mw in &self.middlewares {
            let sc = if mw.can_short_circuit { " [short-circuit]" } else { "" };
            lines.push(format\!("  {}. {}{}", mw.order, mw.name, sc));
            if self.show_config {
                if let Some(config) = &mw.config_summary {
                    lines.push(format\!("     config: {}", config));
                }
            }
        }
        lines.push(format\!("  {}. [Handler]", self.middlewares.len() + 1));

        lines.join("\n")
    }
}
